import React, { useMemo, useState } from "react";

/*
  SystemsOverview.jsx
  - Rendered INSIDE AdminLayout
  - UI-only navigation using window.location (NO react-router-dom)
  - Dummy ML verdict data
*/

// -----------------------------
// Dummy ML Verdict Data
// -----------------------------
const DUMMY_SYSTEMS = [
  {
    id: "sys-1001",
    owner: "Manufacturing / Line A",
    healthScore: 92,
    status: "healthy",
    primaryRootCause: "Hardware",
    confidence: 96,
    lastSeen: new Date(Date.now() - 3 * 60 * 1000).toISOString(),
  },
  {
    id: "sys-1002",
    owner: "Data Center / Rack 7",
    healthScore: 64,
    status: "warning",
    primaryRootCause: "Software",
    confidence: 81,
    lastSeen: new Date(Date.now() - 22 * 60 * 1000).toISOString(),
  },
  {
    id: "sys-1003",
    owner: "Field Device / Pump 4",
    healthScore: 38,
    status: "critical",
    primaryRootCause: "Security",
    confidence: 92,
    lastSeen: new Date(Date.now() - 5 * 60 * 60 * 1000).toISOString(),
  },
  {
    id: "sys-1004",
    owner: "Office / Finance",
    healthScore: 74,
    status: "warning",
    primaryRootCause: "Hardware",
    confidence: 72,
    lastSeen: new Date(Date.now() - 30 * 1000).toISOString(),
  },
  {
    id: "sys-1005",
    owner: "R&D / Lab",
    healthScore: 87,
    status: "healthy",
    primaryRootCause: "Software",
    confidence: 88,
    lastSeen: new Date(Date.now() - 26 * 60 * 60 * 1000).toISOString(),
  },
];

// -----------------------------
// Helpers
// -----------------------------
function relativeTimeFrom(dateIsoString) {
  const then = new Date(dateIsoString).getTime();
  const now = Date.now();
  const d = Math.abs(now - then) / 1000;

  if (d < 60) return `${Math.floor(d)} sec ago`;
  if (d < 3600) return `${Math.floor(d / 60)} min ago`;
  if (d < 86400) return `${Math.floor(d / 3600)} hour${Math.floor(d / 3600) > 1 ? "s" : ""} ago`;
  return `${Math.floor(d / 86400)} day${Math.floor(d / 86400) > 1 ? "s" : ""} ago`;
}

function healthColorClass(score) {
  if (score >= 80) return "text-green-700 bg-green-50";
  if (score >= 50) return "text-yellow-800 bg-yellow-50";
  return "text-red-700 bg-red-50";
}

function rootCauseBadgeClass(cause) {
  switch (cause) {
    case "Hardware":
      return "bg-blue-50 text-blue-700";
    case "Software":
      return "bg-purple-50 text-purple-700";
    case "Security":
      return "bg-red-50 text-red-700";
    default:
      return "bg-gray-100 text-gray-700";
  }
}

// -----------------------------
// Component
// -----------------------------
export default function SystemsOverview() {
  const [statusFilter, setStatusFilter] = useState("All");
  const [rootCauseFilter, setRootCauseFilter] = useState("All");

  const filtered = useMemo(() => {
    return DUMMY_SYSTEMS.filter((s) => {
      if (statusFilter !== "All" && s.status.toLowerCase() !== statusFilter.toLowerCase()) return false;
      if (rootCauseFilter !== "All" && s.primaryRootCause !== rootCauseFilter) return false;
      return true;
    });
  }, [statusFilter, rootCauseFilter]);

  // UI-only navigation (NO router)
  const goToDetails = (id) => {
    window.location.href = `/systems/${id}`;
  };

  return (
    <div className="p-6 bg-gray-50 min-h-[calc(100vh-4rem)]">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:justify-between mb-6 gap-4">
        <div>
          <h1 className="text-2xl font-semibold">Systems Overview</h1>
          <p className="text-sm text-slate-600">
            AI-evaluated system health across all managed devices
          </p>
        </div>

        <div className="flex gap-3">
          <select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)} className="border px-3 py-2 rounded-md">
            <option>All</option>
            <option>Healthy</option>
            <option>Warning</option>
            <option>Critical</option>
          </select>

          <select value={rootCauseFilter} onChange={(e) => setRootCauseFilter(e.target.value)} className="border px-3 py-2 rounded-md">
            <option>All</option>
            <option>Hardware</option>
            <option>Software</option>
            <option>Security</option>
          </select>
        </div>
      </div>

      {/* Table */}
      <div className="bg-white rounded-lg shadow overflow-x-auto">
        <table className="min-w-full divide-y">
          <thead className="bg-gray-50">
            <tr className="text-xs uppercase text-gray-600">
              <th className="px-4 py-3">System ID</th>
              <th className="px-4 py-3">Owner</th>
              <th className="px-4 py-3">Health</th>
              <th className="px-4 py-3">Root Cause</th>
              <th className="px-4 py-3">Confidence</th>
              <th className="px-4 py-3">Last Seen</th>
              <th className="px-4 py-3">Actions</th>
            </tr>
          </thead>

          <tbody className="divide-y">
            {filtered.map((s) => (
              <tr key={s.id} className="hover:bg-gray-50">
                <td className="px-4 py-4">
                  <button onClick={() => goToDetails(s.id)} className="text-sky-600 hover:underline">
                    {s.id}
                  </button>
                </td>
                <td className="px-4 py-4">{s.owner}</td>
                <td className="px-4 py-4">
                  <div className={`w-9 h-9 rounded-full flex items-center justify-center ${healthColorClass(s.healthScore)}`}>
                    {s.healthScore}
                  </div>
                </td>
                <td className="px-4 py-4">
                  <span className={`px-2 py-1 rounded-full text-xs ${rootCauseBadgeClass(s.primaryRootCause)}`}>
                    {s.primaryRootCause}
                  </span>
                </td>
                <td className="px-4 py-4">{s.confidence}%</td>
                <td className="px-4 py-4">{relativeTimeFrom(s.lastSeen)}</td>
                <td className="px-4 py-4">
                  <button
                    onClick={() => goToDetails(s.id)}
                    className="px-3 py-1.5 border rounded-md text-sm hover:bg-gray-50"
                  >
                    Details
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
